const at = $json.access_token || $json.accessToken || $json.token || (($json.data || {}).access_token) || '';
const ra = $json.authorization || $json.Authorization || (($json.data || {}).authorization) || '';
const authorization = ra || (at ? (String(at).startsWith('Bearer ') ? String(at) : 'Bearer ' + at) : '');
if (!authorization) throw new Error('Bearer Sankhya ausente');
return [{ json: {
  source_code: 'romaneio_sankhya_webhook',
  workflow_name: 'PCP | 15A | Sankhya | Ordens de Carga Native',
  authorization,
  list_url: 'https://api.sankhya.com.br/v1/logistica/ordens-carga',
  loadrecords_url: 'https://api.sankhya.com.br/gateway/v1/mge/service.sbr?serviceName=CRUDServiceProvider.loadRecords&outputType=json',
  max_orders: 25,
  max_product_pages: 40,
  max_note_pages: 10,
  max_item_pages: 10,
  include_empty_items: false,
  only_pending: true,
  exclude_status: ['entregue', 'finalizada', 'finalizado', 'fechada', 'fechado', 'cancelada', 'cancelado', 'concluida', 'concluido']
}}];

const cfg = $('Build Config').first().json;
const payload = $input.first().json;

function cleanText(value) {
  return String(value == null ? '' : value).replace(/\s+/g, ' ').trim();
}

function extractOrders(rawPayload) {
  if (Array.isArray(rawPayload)) {
    for (const entry of rawPayload) {
      const nested = extractOrders(entry);
      if (nested.length) return nested;
    }
    return [];
  }

  if (rawPayload && typeof rawPayload === 'object') {
    if (Array.isArray(rawPayload.ordensCarga)) {
      return rawPayload.ordensCarga.filter((item) => item && typeof item === 'object');
    }

    for (const key of ['data', 'items', 'results', 'records', 'content', 'rows', 'value', 'response']) {
      if (Array.isArray(rawPayload[key])) {
        return rawPayload[key].filter((item) => item && typeof item === 'object');
      }
    }
  }

  return [];
}

const ordensCarga = extractOrders(payload);
const outputs = [];

for (const order of ordensCarga) {
  if (outputs.length >= Number(cfg.max_orders || 0)) break;

  const emp = cleanText(order.codigoEmpresa);
  const id = cleanText(order.codigoOrdemCarga || order.codigo || order.codOrdemCarga);
  if (!emp || !id) continue;

  if (cfg.only_pending) {
    const sit = cleanText(order.situacao || order.status || order.statusOrdemCarga).toLowerCase();
    if (sit && cfg.exclude_status.some((status) => sit.includes(cleanText(status).toLowerCase()))) {
      continue;
    }
  }

  outputs.push({ json: {
    authorization: cfg.authorization,
    source_code: cfg.source_code,
    workflow_name: cfg.workflow_name,
    include_empty_items: Boolean(cfg.include_empty_items),
    loadrecords_url: cfg.loadrecords_url,
    max_product_pages: Number(cfg.max_product_pages || 40),
    max_note_pages: Number(cfg.max_note_pages || 10),
    max_item_pages: Number(cfg.max_item_pages || 10),
    order_row: order,
    codigo_empresa: emp,
    codigo_ordem_carga: id
  }});
}

return outputs;

const sourceRows = $('Expand Orders').all();

function unwrap(value) {
  if (value && typeof value === 'object' && '$' in value) return value.$;
  return value;
}

function cleanText(value) {
  const raw = unwrap(value);
  return String(raw == null ? '' : raw).replace(/\s+/g, ' ').trim();
}

function parseNumber(value) {
  const raw = unwrap(value);
  if (raw == null || raw === '') return 0;
  if (typeof raw === 'number') return raw;

  let text = cleanText(raw);
  if (!text) return 0;

  if (text.includes(',') && text.includes('.')) {
    if (text.lastIndexOf(',') > text.lastIndexOf('.')) {
      text = text.replace(/\./g, '').replace(',', '.');
    } else {
      text = text.replace(/,/g, '');
    }
  } else {
    text = text.replace(',', '.');
  }

  const parsed = Number(text);
  return Number.isFinite(parsed) ? parsed : 0;
}

function normalizeHttpBody(body) {
  if (typeof body === 'string') {
    try {
      return JSON.parse(body);
    } catch (error) {
      return { raw_body: body };
    }
  }

  return body && typeof body === 'object' ? body : {};
}

function extractRowsByKeys(payload, requiredKeys) {
  const rows = [];
  const seen = new Set();
  const queue = [normalizeHttpBody(payload)];

  while (queue.length) {
    const current = queue.shift();

    if (Array.isArray(current)) {
      for (const item of current) queue.push(item);
      continue;
    }

    if (!current || typeof current !== 'object') continue;

    const isMatch = requiredKeys.every((key) => key in current);
    if (isMatch) {
      const fingerprint = JSON.stringify(current);
      if (!seen.has(fingerprint)) {
        seen.add(fingerprint);
        rows.push(current);
      }
      continue;
    }

    for (const value of Object.values(current)) {
      if (value && typeof value === 'object') queue.push(value);
    }
  }

  return rows;
}

function buildProdutoLoadRecordsBody(offsetPage) {
  return {
    serviceName: 'CRUDServiceProvider.loadRecords',
    requestBody: {
      dataSet: {
        rootEntity: 'Produto',
        includePresentationFields: 'S',
        offsetPage: String(offsetPage),
        entity: [
          {
            path: '',
            fieldset: {
              list: 'CODPROD,DESCRPROD,CODVOL,M3'
            }
          }
        ]
      }
    }
  };
}

function buildCabecalhoLoadRecordsBody(codigoEmpresa, codigoOrdemCarga, offsetPage) {
  return {
    serviceName: 'CRUDServiceProvider.loadRecords',
    requestBody: {
      dataSet: {
        rootEntity: 'CabecalhoNota',
        includePresentationFields: 'S',
        offsetPage: String(offsetPage),
        criteria: {
          expression: {
            $: 'this.CODEMP = ? and this.ORDEMCARGA = ?'
          },
          parameter: [
            {
              type: 'I',
              $: String(codigoEmpresa)
            },
            {
              type: 'I',
              $: String(codigoOrdemCarga)
            }
          ]
        },
        entity: [
          {
            path: '',
            fieldset: {
              list: 'NUNOTA,NUMNOTA,CODEMP,ORDEMCARGA,CODPARC,DTNEG,VLRNOTA'
            }
          }
        ]
      }
    }
  };
}

function buildItemLoadRecordsBody(nunota, offsetPage) {
  return {
    serviceName: 'CRUDServiceProvider.loadRecords',
    requestBody: {
      dataSet: {
        rootEntity: 'ItemNota',
        includePresentationFields: 'S',
        offsetPage: String(offsetPage),
        criteria: {
          expression: {
            $: 'this.NUNOTA = ?'
          },
          parameter: [
            {
              type: 'I',
              $: String(nunota)
            }
          ]
        },
        entity: [
          {
            path: '',
            fieldset: {
              list: 'NUNOTA,SEQUENCIA,CODPROD,QTDNEG,VLRUNIT,VLRTOT,CODVOL'
            }
          }
        ]
      }
    }
  };
}

async function fetchLoadRecordsPages(config) {
  const rows = [];
  const seenRows = new Set();
  const pageDebug = [];

  for (let offsetPage = 0; offsetPage < Number(config.maxPages || 1); offsetPage += 1) {
    try {
      const response = await this.helpers.httpRequest({
        method: 'POST',
        url: config.url,
        headers: {
          accept: 'application/json',
          'Content-Type': 'application/json',
          Authorization: config.authorization
        },
        body: config.buildBody(offsetPage),
        json: true,
        returnFullResponse: true,
        ignoreHttpStatusErrors: true
      });

      const payload = normalizeHttpBody(response.body);
      const pageRows = extractRowsByKeys(payload, config.requiredKeys || []);
      let freshRows = 0;

      for (const row of pageRows) {
        const fingerprint = JSON.stringify(row);
        if (!seenRows.has(fingerprint)) {
          seenRows.add(fingerprint);
          rows.push(row);
          freshRows += 1;
        }
      }

      pageDebug.push({
        offset_page: offsetPage,
        status_code: response.statusCode,
        ok: response.statusCode >= 200 && response.statusCode < 400,
        row_count: pageRows.length,
        fresh_rows: freshRows,
        error: payload.error || null
      });

      if (!pageRows.length || !freshRows) break;
    } catch (error) {
      pageDebug.push({
        offset_page: offsetPage,
        ok: false,
        error: String(error).slice(0, 300)
      });
      break;
    }
  }

  return { rows, pageDebug };
}

function parseDateTime(value, fallback) {
  const text = cleanText(value);
  if (!text) return fallback;

  const direct = new Date(text);
  if (!Number.isNaN(direct.getTime())) return direct.toISOString();

  const match = text.match(/^(\d{2})\/(\d{2})\/(\d{4})(?:\s+(\d{2}):(\d{2})(?::(\d{2}))?)?$/);
  if (match) {
    const [, dd, mm, yyyy, hh = '00', mi = '00', ss = '00'] = match;
    return new Date(Date.UTC(Number(yyyy), Number(mm) - 1, Number(dd), Number(hh), Number(mi), Number(ss))).toISOString();
  }

  return fallback;
}

function buildEventTimestamp(dateValue, timeValue, fallback) {
  const dateText = cleanText(dateValue);
  const timeText = cleanText(timeValue) || '00:00';
  return dateText ? parseDateTime(dateText + ' ' + timeText, fallback) : fallback;
}

function hashText(text) {
  let hash = 0;
  for (let index = 0; index < text.length; index += 1) {
    hash = ((hash << 5) - hash) + text.charCodeAt(index);
    hash |= 0;
  }
  return Math.abs(hash).toString(16);
}

function buildProductMap(produtoRows) {
  const map = new Map();

  for (const row of produtoRows) {
    const codigo = cleanText(row.CODPROD);
    if (!codigo) continue;

    map.set(codigo, {
      codigo,
      descricao: cleanText(row.DESCRPROD),
      unidade: cleanText(row.CODVOL),
      metro_cubico: parseNumber(row.M3)
    });
  }

  return map;
}

function normalizeItemRow(row, notaRow, productMap) {
  const sku = cleanText(row.CODPROD);
  const product = productMap.get(sku) || {};
  const descricao = cleanText(product.descricao || row.DESCRPROD || '');
  const unidade = cleanText(row.CODVOL || product.unidade || 'UN') || 'UN';
  const quantidade = parseNumber(row.QTDNEG);
  const valorUnitario = parseNumber(row.VLRUNIT);
  const valorTotal = parseNumber(row.VLRTOT);
  const m3 = parseNumber(product.metro_cubico || 0);

  if (!sku && !descricao) return null;

  const produto = cleanText(sku && descricao ? sku + ' - ' + descricao : (descricao || sku));

  return {
    sku,
    descricao: descricao || produto,
    produto,
    unidade,
    tipo_produto: 'PRODUTO ACABADO',
    quantidade: Number(quantidade.toFixed(6)),
    quantidade_neg: Number(quantidade.toFixed(6)),
    quantidade_vol: 0,
    quantity_total: Number(quantidade.toFixed(6)),
    valor_unitario: Number(valorUnitario.toFixed(6)),
    valor_total: Number(valorTotal.toFixed(6)),
    metro_cubico: Number(m3.toFixed(6)),
    codigo_nota: cleanText(notaRow.NUNOTA || row.NUNOTA || ''),
    numero_nota: cleanText(notaRow.NUMNOTA || ''),
    sequencia: Number(parseNumber(row.SEQUENCIA)),
    cfop: cleanText(row.CFOP || ''),
    ncm: cleanText(row.NCM || '')
  };
}

const outputs = [];
const firstSource = ((sourceRows[0] || {}).json) || {};
const loadrecordsUrl = firstSource.loadrecords_url || 'https://api.sankhya.com.br/gateway/v1/mge/service.sbr?serviceName=CRUDServiceProvider.loadRecords&outputType=json';
let produtoRows = [];
let produtosDebug = [];
let productMap = new Map();

if (firstSource.authorization) {
  const produtosResult = await fetchLoadRecordsPages.call(this, {
    url: loadrecordsUrl,
    authorization: firstSource.authorization,
    maxPages: Number(firstSource.max_product_pages || 40),
    buildBody: (offsetPage) => buildProdutoLoadRecordsBody(offsetPage),
    requiredKeys: ['CODPROD', 'DESCRPROD']
  });

  produtoRows = produtosResult.rows;
  produtosDebug = produtosResult.pageDebug;
  productMap = buildProductMap(produtoRows);
}

for (let index = 0; index < sourceRows.length; index += 1) {
  const source = ((sourceRows[index] || {}).json) || {};
  const order = source.order_row || {};
  const currentLoadrecordsUrl = source.loadrecords_url || loadrecordsUrl;

  const notasResult = await fetchLoadRecordsPages.call(this, {
    url: currentLoadrecordsUrl,
    authorization: source.authorization,
    maxPages: Number(source.max_note_pages || 10),
    buildBody: (offsetPage) => buildCabecalhoLoadRecordsBody(source.codigo_empresa, source.codigo_ordem_carga, offsetPage),
    requiredKeys: ['NUNOTA', 'NUMNOTA', 'CODEMP', 'ORDEMCARGA']
  });

  const notasRows = notasResult.rows;
  const notasDebug = notasResult.pageDebug;
  const itemnotaDebug = [];
  const itens = [];
  const notasCodigos = [];
  const notasValorMap = new Map();
  const produtosNaoLocalizados = [];

  for (const notaRow of notasRows) {
    const nunota = cleanText(notaRow.NUNOTA);
    const numnota = cleanText(notaRow.NUMNOTA);

    if (!nunota) {
      itemnotaDebug.push({
        nunota,
        numnota,
        ok: false,
        error: 'nunota_vazia'
      });
      continue;
    }

    if (!notasCodigos.includes(numnota || nunota)) {
      notasCodigos.push(numnota || nunota);
    }

    if (!notasValorMap.has(nunota)) {
      notasValorMap.set(nunota, parseNumber(notaRow.VLRNOTA));
    }

    const itemResult = await fetchLoadRecordsPages.call(this, {
      url: currentLoadrecordsUrl,
      authorization: source.authorization,
      maxPages: Number(source.max_item_pages || 10),
      buildBody: (offsetPage) => buildItemLoadRecordsBody(nunota, offsetPage),
      requiredKeys: ['NUNOTA', 'SEQUENCIA', 'CODPROD', 'QTDNEG']
    });

    itemnotaDebug.push({
      nunota,
      numnota,
      row_count: itemResult.rows.length,
      pages: itemResult.pageDebug
    });

    for (const row of itemResult.rows) {
      const item = normalizeItemRow(row, notaRow, productMap);
      if (item && item.quantity_total > 0) {
        if (item.sku && !productMap.has(item.sku) && !produtosNaoLocalizados.includes(item.sku)) {
          produtosNaoLocalizados.push(item.sku);
        }
        itens.push(item);
      }
    }
  }

  const valorTotal = Array.from(notasValorMap.values()).reduce((sum, value) => sum + parseNumber(value), 0);
  const nowIso = new Date().toISOString();
  const fallbackDate = notasRows[0] ? cleanText(notasRows[0].DTNEG) : '';
  const eventAt = buildEventTimestamp(order.dataPrevistaSaida || order.dataInicio || fallbackDate, order.horaSaida || '', nowIso);

  const fingerprint = JSON.stringify({
    codigo: source.codigo_ordem_carga,
    empresa: source.codigo_empresa,
    notas: notasCodigos,
    itens: itens.length,
    valor_total: valorTotal
  });

  const eventId = (source.source_code || 'romaneio_sankhya_webhook')
    + ':' + cleanText(source.codigo_ordem_carga)
    + ':' + eventAt.replace(/[:\-]/g, '').replace('.000Z', 'Z')
    + ':' + hashText(fingerprint);

  outputs.push({
    json: {
      source_code: source.source_code || 'romaneio_sankhya_webhook',
      workflow_name: source.workflow_name || 'PCP | 15A | Sankhya | Ordens de Carga Native',
      should_ingest: Boolean(source.include_empty_items) || itens.length > 0,
      payload: {
        event_id: eventId,
        event_type: 'update',
        event_at: eventAt,
        romaneio: {
          codigo: cleanText(source.codigo_ordem_carga),
          empresa: cleanText(source.codigo_empresa),
          status: cleanText(order.situacao || order.status || order.statusOrdemCarga || '1') || '1',
          pedido: notasCodigos.filter(Boolean).join(', '),
          parceiro: cleanText(order.nomeTransportadora || ''),
          cidade: cleanText(order.nomeRegiao || ''),
          valor_total: Number(valorTotal.toFixed(2)),
          itens
        }
      },
      meta: {
        polling: true,
        native_n8n: true,
        workflow_name: source.workflow_name || 'PCP | 15A | Sankhya | Ordens de Carga Native',
        items_source: itens.length ? 'produto_catalogo_cabecalhonota_itemnota' : 'produto_catalogo_sem_itens',
        items_count: itens.length,
        produtos_catalogo_count: produtoRows.length,
        produtos_catalogo_debug: produtosDebug,
        notas_cabecalho_count: notasRows.length,
        notas_cabecalho_debug: notasDebug,
        notas_codigos: notasCodigos.filter(Boolean),
        notas_vinculadas_rows: notasRows,
        itemnota_debug: itemnotaDebug,
        produtos_nao_localizados: produtosNaoLocalizados,
        order_row: order
      }
    }
  });
}

return outputs;

var esc = function(value) {
  var raw = JSON.stringify(value == null ? {} : value);
  return raw.replace(/\\/g, '\\\\').replace(/'/g, "''");
};
var escT = function(v) { return String(v == null ? '' : v).replace(/\\/g, '\\\\').replace(/'/g, "''"); };
var rom = ($json.payload || {}).romaneio || {};
var eid = escT(($json.payload || {}).event_id || '');
var rc = escT(rom.codigo || '');
var ic = Array.isArray(rom.itens) ? rom.itens.length : 0;
var shouldIngest = $json.should_ingest === true;
var sql;
if (!shouldIngest) {
  sql = 'select jsonb_build_object(\n'
    + "  'event_id','" + eid + "',\n"
    + "  'romaneio_code','" + rc + "',\n"
    + "  'item_count'," + ic + ",\n"
    + "  'ingest', jsonb_build_object('status','noop','reason','sem_itens')\n"
    + ') as result;';
} else {
  sql = 'select jsonb_build_object(\n'
    + "  'event_id','" + eid + "',\n"
    + "  'romaneio_code','" + rc + "',\n"
    + "  'item_count'," + ic + ",\n"
    + "  'ingest', ops.ingest_romaneio_event_payload(\n"
    + "    '" + escT($json.source_code || 'romaneio_sankhya_webhook') + "',\n"
    + "    '" + esc($json.payload) + "'::jsonb,\n"
    + "    '" + esc($json.meta) + "'::jsonb\n"
    + "  )\n) as result;";
}
return { json: { ...$json, sql_query: sql } };

var row = $json || {};
var result = row.result != null ? row.result : row;
if (typeof result === 'string') { try { result = JSON.parse(result); } catch(e) { result = {status:'unknown'}; } }
var ingest = result.ingest || {};
return { json: {
  ok: ['processed','duplicate_ignored','noop'].indexOf(ingest.status || result.status) >= 0,
  workflow: 'PCP | 15A | Sankhya | Ordens de Carga Native',
  mode: 'polling_native', ...result, ingest: ingest
}};
